#include <stdio.h>
#include <stdint.h>

static inline uint32_t minCost(uint32_t n) {
    const int L = 31; // we work with 31 bits (0 … 30)
    uint32_t best = UINT32_MAX; // large sentinel
    for (int l = 0; l <= L; ++l) {
        for (int r = l; r <= L; ++r) {
            uint32_t val;
            if (l == L) {
                val = 0; // all zeros
            } else {
                uint32_t high = 1u << (L - l);
                uint32_t low = (r == L) ? 0u : (1u << (L - r));
                val = high - low;
            }
            if (val >= n) {
                uint32_t diff = val - n;
                if (diff < best) best = diff;
            }
        }
    }
    return best;
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        uint32_t N; scanf("%u", &N);
        printf("%u\n", minCost(N));
    }
    return 0;
}

