#include <bits/stdc++.h>
using namespace std;

static inline uint32_t minCost(uint32_t n) {
    const int L = 31; // enough for N < 2^30
    uint32_t best = UINT32_MAX;
    for (int l = 0; l <= L; ++l) {
        for (int r = l; r <= L; ++r) {
            uint32_t val;
            if (l == L) {
                val = 0;
            } else {
                uint32_t high = 1u << (L - l);
                uint32_t low = (r == L) ? 0u : (1u << (L - r));
                val = high - low;
            }
            if (val >= n) {
                best = min(best, val - n);
            }
        }
    }
    return best;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while (T--) {
        uint32_t N; cin >> N;
        cout << minCost(N) << '\n';
    }
    return 0;
}

