import sys

def min_cost(n: int) -> int:
    L = 31  # enough for N < 2**30
    best = 1 << 60
    for l in range(L + 1):
        for r in range(l, L + 1):
            if l == L:
                val = 0
            else:
                high = 1 << (L - l)
                low = 0 if r == L else 1 << (L - r)
                val = high - low
            if val >= n:
                diff = val - n
                if diff < best:
                    best = diff
    return best

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        out.append(str(min_cost(N)))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    solve()

